import Foundation
import UIKit
import ScanbotSDK
import ScanbotSDKNativeWrapper

@objc
public class RNScanbotCroppingLegacyView: UIView {
    
    var editingViewController: SBSDKImageEditingViewController!
    var isAttached = false
    var defaultValues = CroppingViewDefaultValues()
    
    @objc var onCroppedAreaResult: RCTDirectEventBlock?
    @objc var onError: RCTDirectEventBlock?
    
    @objc public var eventDelegate: RNScanbotCroppingViewEventsDelegate?
    
    public override init(frame: CGRect) {
        editingViewController = SBSDKImageEditingViewController.create(
            image: UIImage.placeholderImage(),
            polygon: nil
        )
        super.init(frame: frame)
        
        self.eventDelegate = RNScanbotCroppingViewEventsDelegate(
            onExtractArea: self.onCroppedAreaResultEvent,
            onError: self.onErrorEvent
        )
        
        setDefaultValues()
    }
    
    @objc public init(frame: CGRect, eventDelegate: RNScanbotCroppingViewEventsDelegate){
        editingViewController = SBSDKImageEditingViewController.create(
            image: UIImage.placeholderImage(),
            polygon: nil
        )
        self.eventDelegate = eventDelegate
        
        super.init(frame: frame)
        
        setDefaultValues()
    }
    
    public required init?(coder: NSCoder) {
        fatalError("init(coder:) has not been implemented")
    }
    
    public override func didMoveToWindow() {
        
        if(window != nil && !isAttached){
            isAttached = self.attachViewController(viewController: editingViewController)
        }
        
        super.didMoveToWindow()
    }
    
    public override func removeFromSuperview() {
        self.detachViewController(viewController: editingViewController)
        eventDelegate = nil
        super.removeFromSuperview()
    }
    
    private func setDefaultValues(){
        editingViewController.edgeColor = defaultValues.edgeColor
        editingViewController.edgeLineWidth = defaultValues.edgeLineWidth
        editingViewController.magneticEdgeColor = defaultValues.edgeColorOnLine
        editingViewController.anchorPointsColor = defaultValues.anchorPointsColors
    }
    
    //MARK: Properties
    @objc
    public func setImageFileSrc(_ value: String?){
    
        guard let value = value else {
            return
        }
        
        do {
            setImageSource(try SBImage(value).uiImage)
        } catch {
            eventDelegate?.onError(error.localizedDescription)
        }
    }
    
    @objc
    public func setImageRefSrc(_ value: String? ){
        
        guard let value = value else {
            return
        }
        
        guard let uuid = UUID(uuidString: value),
              let image = SBSDKImageRef(uniqueId: uuid, acquireStrongReference: false).toUIImage()
        else {
            eventDelegate?.onError("Invalid ImageRef uuid")
            return
        }
        
        setImageSource(image)
    }
    
    @objc
    public func setEdgeColor(_ value: UIColor?){
        editingViewController.edgeColor = value ?? defaultValues.edgeColor
    }
    
    @objc
    public func setEdgeLineWidth(_ value: NSNumber?){
        if (value != nil) {
            editingViewController.edgeLineWidth = CGFloat(value!.floatValue)
        } else {
            editingViewController.edgeLineWidth = defaultValues.edgeLineWidth
        }
    }
    
    @objc
    public func setEdgeColorOnLine(_ value: UIColor?){
        editingViewController.magneticEdgeColor = value ?? defaultValues.edgeColorOnLine
    }
    
    @objc
    public func setAnchorPointsColor(_ value: UIColor?){
        editingViewController.anchorPointsColor = value ?? defaultValues.anchorPointsColors
    }
    
    //MARK: Methods
    
    @objc
    public func resetPolygon(){
        editingViewController.resetPolygon()
    }
    
    @objc
    public func detectPolygon(){
        editingViewController.detectPolygon()
    }
    
    @objc
    public func rotate(_ value: Bool){
        editingViewController.rotateInputImageClockwise(value, animated: true)
    }
    
    @objc
    public func extractCroppedArea(){
        
        let result = CroppingViewCroppedAreaResult(
            polygon: editingViewController.polygon.polygonPoints(),
            rotation: SBSDKImageRotation(rawValue: (editingViewController.rotations)) ?? SBSDKImageRotation.none,
            sourceImage: SBSDKImageRef.fromUIImage(image: editingViewController.croppedImage!)
        )
        
        guard let data = try? JSONEncoder().encode(result),
              let json = String(data: data, encoding: .utf8)
        else {
            eventDelegate?.onError("Could not serialize the result")
            return
        }
        
        eventDelegate?.onExtractCroppingArea(json)
    }
    
    private func setImageSource(_ image: UIImage){
        
        if(isAttached){
            self.detachViewController(viewController: editingViewController)
        }
        
        editingViewController = editingViewController.setImage(image: image)
        
        if(isAttached){
            isAttached = self.attachViewController(viewController: editingViewController)
        }
        
    }
    
    private func onErrorEvent(_ message: String){
        onError?(["result": message])
    }
    
    private func onCroppedAreaResultEvent(_ result: String){
        onCroppedAreaResult?(["result": result])
    }
}
